fieldUpdates.formula:
IF( TEXT(Factura__r.Divisa_Comprobante__c) <> "ARS", 
IF( Tipo_de_Cambio__c > 0, ROUND( Importe__c / Tipo_de_Cambio__c, 2 ),
ROUND( Importe__c / Factura__r.Tipo_de_Cambio_del_Comprobante__c, 2 )
),
Importe__c
)

IF( TEXT(Factura__r.Divisa_Comprobante__c) <> "ARS",IF( Tipo_de_Cambio__c > 0, ROUND( Importe__c / Tipo_de_Cambio__c, 2 ), 
ROUND( Importe__c / Factura__r.Tipo_de_Cambio_del_Comprobante__c, 2 ) 
), 
Importe__c 
)

IF( OR( ISPICKVAL( Factura__r.Divisa_Comprobante__c, "USD" ), ISPICKVAL( Factura__r.Divisa_Comprobante__c, "EUR" ) ), 
	IF(Factura__r.Total_Comprobante__c <= Factura__r.Obtentor__r.Umbral_Importe__c, 
		IF(Factura__r.Saldo_a_Cobrar_Comprobante__c - Importe_Aplicar__c <= Factura__r.Total_Comprobante__c * Factura__r.Obtentor__r.Umbral_Porcentaje__c, 
			Factura__r.Saldo_a_Cobrar_Comprobante__c - Importe_Aplicar__c, 
			0
		), 
		IF(Factura__r.Saldo_a_Cobrar_Comprobante__c - Importe_Aplicar__c <= Factura__r.Obtentor__r.Umbral_Base__c, 
			Factura__r.Saldo_a_Cobrar_Comprobante__c - Importe_Aplicar__c, 
			0
		) 
	), 
	IF( ( Factura__r.Total_Comprobante__c / Factura__r.Tipo_de_Cambio_Actualizado__c ) <= Factura__r.Obtentor__r.Umbral_Importe__c, 
		IF( ( Factura__r.Saldo_a_Cobrar_Comprobante__c - Importe_Aplicar__c ) / Factura__r.Tipo_de_Cambio_Actualizado__c <= ( Factura__r.Total_Comprobante__c / Factura__r.Tipo_de_Cambio_Actualizado__c ) * Factura__r.Obtentor__r.Umbral_Porcentaje__c, 
			Factura__r.Saldo_a_Cobrar_Comprobante__c - Importe_Aplicar__c, 
			0
		), 
		IF( ( Factura__r.Saldo_a_Cobrar_Comprobante__c - Importe_Aplicar__c ) / Factura__r.Tipo_de_Cambio_Actualizado__c <= Factura__r.Obtentor__r.Umbral_Base__c, 
			Factura__r.Saldo_a_Cobrar_Comprobante__c - Importe_Aplicar__c, 
			0
		) 
	) 
)
